  1	import React, { FC, useCallback } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	import { VirtualMachineModel } from 'src/views/dashboard-extensions/utils';
  4	
  5	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
  6	import HidableTooltip from '@kubevirt-utils/components/HidableTooltip/HidableTooltip';
  7	import { logITFlowEvent } from '@kubevirt-utils/extensions/telemetry/telemetry';
  8	import { CANCEL_CREATE_VM_BUTTON_CLICKED } from '@kubevirt-utils/extensions/telemetry/utils/constants';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { getResourceUrl } from '@kubevirt-utils/resources/shared';
 11	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 12	import {
 13	  Button,
 14	  ButtonVariant,
 15	  Split,
 16	  SplitItem,
 17	  Stack,
 18	  TooltipPosition,
 19	} from '@patternfly/react-core';
 20	
 21	import useStatusActionButtons from './useStatusActionButtons';
 22	
 23	type ActionButtonsProps = {
 24	  isLoading?: boolean;
 25	  onCreate: () => void;
 26	  onCustomize: () => void;
 27	  onViewYAML: () => void;
 28	};
 29	
 30	const ActionButtons: FC<ActionButtonsProps> = ({
 31	  isLoading = false,
 32	  onCreate,
 33	  onCustomize,
 34	  onViewYAML,
 35	}) => {
 36	  const navigate = useNavigate();
 37	
 38	  const [activeNamespace] = useActiveNamespace();
 39	
 40	  const { t } = useKubevirtTranslation();
 41	
 42	  const {
 43	    instanceTypeVMState: { vmName },
 44	  } = useInstanceTypeVMStore();
 45	
 46	  const onCancel = useCallback(() => {
 47	    logITFlowEvent(CANCEL_CREATE_VM_BUTTON_CLICKED, null, { vmName: vmName });
 48	    navigate(getResourceUrl({ activeNamespace, model: VirtualMachineModel }));
 49	  }, [activeNamespace, navigate, vmName]);
 50	
 51	  const { disableButtonTooltipContent, isCreationDisabled, isViewYAMLDisabled } =
 52	    useStatusActionButtons(isLoading);
 53	
 54	  return (
 55	    <Split hasGutter>
 56	      <SplitItem>
 57	        <HidableTooltip
 58	          content={<Stack>{disableButtonTooltipContent}</Stack>}
 59	          hidden={!isCreationDisabled}
 60	          position={TooltipPosition.top}
 61	        >
 62	          <Button
 63	            isAriaDisabled={isCreationDisabled}
 64	            isLoading={isLoading}
 65	            onClick={onCreate}
 66	            variant={ButtonVariant.primary}
 67	          >
 68	            {t('Create VirtualMachine')}
 69	          </Button>
 70	        </HidableTooltip>
 71	      </SplitItem>
 72	      <SplitItem>
 73	        <HidableTooltip
 74	          content={<Stack>{disableButtonTooltipContent}</Stack>}
 75	          hidden={!isCreationDisabled}
 76	          position={TooltipPosition.top}
 77	        >
 78	          <Button
 79	            isDisabled={isCreationDisabled}
 80	            isLoading={isLoading}
 81	            onClick={onCustomize}
 82	            variant={ButtonVariant.secondary}
 83	          >
 84	            {t('Customize VirtualMachine')}
 85	          </Button>
 86	        </HidableTooltip>
 87	      </SplitItem>
 88	
 89	      <SplitItem>
 90	        <Button onClick={onCancel} variant={ButtonVariant.link}>
 91	          {t('Cancel')}
 92	        </Button>
 93	      </SplitItem>
 94	      <SplitItem isFilled />
 95	      <SplitItem>
 96	        <Button
 97	          isDisabled={isViewYAMLDisabled}
 98	          onClick={onViewYAML}
 99	          variant={ButtonVariant.secondary}
100	        >
101	          {t('View YAML & CLI')}
102	        </Button>
103	      </SplitItem>
104	    </Split>
105	  );
106	};
107	
108	export default ActionButtons;

